INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (1525, 'The Haunted World of Edward D. Wood, Jr.', 'Film', 'Documentary', 'The strange life and the wonderfully awful films of 1950''s Hollywood Z movie director Ed Wood are profiled in this documentary that was conceived of and researched several years before commercial-filmmaker Tim Burton made his feature film tribute. Actually, Wood does not appear much in this film. Rather, it centers on the lives and thoughts of his entourage and those who knew him. Among those interviewed are Wood''s former lover and star of his earliest films, Dolores Fuller, whom he abruptly replaced in the middle of Bride of the Monster with actress Loretta King who is also interviewed.', 1996, 10.0, '2025-12-12 16:15:22.117375', 'https://image.tmdb.org/t/p/w500/rarwGANB2L4EcxInVw1Q8TgcfU1.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (3450, 'Stiff Upper Lips', 'Film', 'Comedy', 'Stiff Upper Lips is a broad parody of British period films, especially the lavish Merchant-Ivory productions of the ''eighties and early ''nineties. Although it specifically targets A Room with a View, Chariots of Fire, Maurice, A Passage to India, and many other films, in a more general way Stiff Upper Lips satirises popular perceptions of certain Edwardian traits: propriety, sexual repression, xenophobia, and class snobbery.', 1998, 10.0, '2025-12-12 16:15:23.049117', 'https://image.tmdb.org/t/p/w500/qozMEPtSjU3bvKS9E4DNYzW1h8u.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (4514, 'The Tic Code', 'Film', '', 'A 10 year old gifted boy wants to be a jazz pianist much to the chagrin of his more classical oriented piano instructor. With his mother''s help, he is an underage regular at a local nightspot, where he is teamed up with a sax superstar. Both come to learn that each suffers from Tourette''s Syndrome (thus the film title). The older man has developed mannerisms to cover up his own fallibilities and resents the boy and his mother''s acceptance of the disease.', 2000, 10.0, '2025-12-12 16:15:23.681958', 'https://image.tmdb.org/t/p/w500/8R03pVm4ECjvITfZ7JKyvFIM49r.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (14833, 'Dinosaurs!  A Fun-Filled Trip Back In Time', 'Film', '', 'The video—with beginning scenes filmed in 1987—begins with a young boy named Phillip (played by Fred Savage) sitting in his bedroom, listening to loud music, and struggling to find an idea for a class report on a science topic. While struggling to find some ideas-and annoying his mother (offscreen) with his loud music- a song plays on his boom box, titled Mesozoic Mind, and the song provides him with an inspiration for his report: DINOSAURS!  Philip then goes to sleep and has a dream where he discovers that the search for the truth about these magnificent animals and their astonishing 160-million-year success on earth is probably the most fascinating speculation there is. Phillip then finishes his report and presents it to the class. The class report is then covered through the 1980 claymation short Dinosaur by Will Vinton Productions.', 1987, 10.0, '2025-12-12 16:15:58.036397', 'https://image.tmdb.org/t/p/w500/yrho3PbjV6MqxsCpLSWrwwut4q6.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (15717, 'The Flight That Fought Back', 'Film', 'Documentary, Drama', 'A docudrama about the efforts of the passengers aboard United Airlines Flight 93 to derail the 9/11 terrorists plan for the hijacked airliner.', 2004, 10.0, '2025-12-12 16:16:02.816857', 'https://image.tmdb.org/t/p/w500/xHVmgQjBIPWWW34Tpjc6tRF8Mbo.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (16853, 'My Foolish Heart', 'Film', '', 'After a long absence, Mary Jane visits her schoolfriend Eloise, and Eloise''s daughter Ramona. Eloise drinks too much and is unhappily married to Lew Wengler. Eloise falls asleep and remembers her time with her true love, Walt Dreiser, at the beginning of the Second World War. She recalls the events that lead up to her split with Mary Jane, and how Lew married Eloise rather than Mary Jane.', 1950, 10.0, '2025-12-12 16:16:09.589666', 'https://image.tmdb.org/t/p/w500/hTeRZeDAX3UUgGnfzBqGUwWyAI6.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (18700, 'Canned Dreams', 'Film', 'Documentary', 'A simple can of ravioli propels this spectacular 30,000-kilometre, eight-country journey through all phases of food production and the far flung sources of international ingredients. A dream-like voyage with glimpses of disconcerting realities, the story begins with a single mother toiling in one of the biggest open pit mines in Brazil and ends on the shelf of a grocery store in Finland. Along the way, the workers whose calloused hands mine, raise and harvest each ingredient reveal their dreams and hopes, like the Danish pig farmer who loves his sows but longs for a girlfriend, and the Portuguese tomato picker who wants to stay healthy long enough to pay her daughters way through university. Sumptuous photography and impressive sound design make an eloquent statement about our modern, globalized world, making us aware of the hundreds of invisible people who prepare the food we eat every day. -Gisèle Gordon (HotDocs.ca)', 2012, 10.0, '2025-12-12 16:16:20.841744', 'https://image.tmdb.org/t/p/w500/cwyBaaRT71QSn04OQpMhDGZUrr4.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (19145, 'The Union', 'Film', 'Music, Documentary', 'In November 2009, filmmaker Cameron Crowe began filming a behind-the-scenes look at the creation of the album The Union, a collaboration between musicians Elton John and Leon Russell, who hadn''t spoken to one another in 38 years prior to beginning work on the album. In addition, the documentary offers a rare glimpse into the process John goes through to create and compose his music. Featured in the film are musicians Neil Young, Brian Wilson, Booker T. Jones, steel guitarist Robert Randolph, Don Was and a 10-piece gospel choir who all contribute to the album, which is produced by award-winning producer T-Bone Burnett. Musician Stevie Nicks and John''s long-time lyricist Bernie Taupin also appear.', 2012, 10.0, '2025-12-12 16:16:23.781403', 'https://m.media-amazon.com/images/M/MV5BMjI0ODAwMTc0OV5BMl5BanBnXkFtZTcwNzg5NDk4Nw@@._V1_SX300.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (20701, 'The Late, Great Planet Earth', 'Film', 'Documentary', 'The Late, Great Planet Earth is the title of a best-selling 1970 book co-authored by Hal Lindsey and Carole C. Carlson, and first published by Zondervan. The book was adapted in 1979 into a movie. The Late, Great Planet Earth is a treatment of literalist, premillennial, dispensational eschatology. As such, it compared end-time prophecies in the Bible with then-current events in an attempt to broadly predict future scenarios leading to the rapture of believers before the tribulation and Second Coming of Christ to establish his thousand-year (i.e. millennial) Kingdom on Earth.', 1979, 10.0, '2025-12-12 16:16:34.397638', 'https://image.tmdb.org/t/p/w500/xqHt4IQcH3caAiKbcImyCldu6gk.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (21829, 'The White Shadow', 'Film', '', 'The White Shadow is a British drama film directed by Graham Cutts based on the novel "Children of Chance" by Michael Morton. Alfred Hitchcock worked on it as assistant director and also handled the writing, editing, and art direction.  The film was long thought to be lost. In August 2011, it was announced that the first three reels of the six-reel picture had been found in a garden shed and donated to the NFPF. The film cans were mislabled Two Sisters and Unidentified American Film and only later identified. The film was restored by Park Road Studios and is now in the New Zealand Film Archive.', 1924, 10.0, '2025-12-12 16:16:43.120338', 'https://image.tmdb.org/t/p/w500/gtfnuORiotKI18g0YBeG34rugdZ.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (22102, 'هیچ کجا هیچ کس', 'Film', 'Mystery, Crime, Drama', '', 2013, 10.0, '2025-12-12 16:16:45.308230', 'https://image.tmdb.org/t/p/w500/8BzFyXeHSDU9f5RE1EbdjYJx0L5.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (22129, 'The Guide', 'Film', 'Comedy', 'Nine frustrated young architects in an equally frustrated city. A comedy about sexuality, Athens and modern Greeks.  Iasonas arrives in Athens starting his new ambitious career as “architects’ guide”. His group consists of international students of architecture, finishing their Erasmus in Thessaloniki. Soon Iasonas faces the contradicting wishes of the students who prefer a day-long coffee or a visit to a graveyard than a guide to the Acropolis. Meanwhile, he meets back with his once (more than just a) best friend Mirsini. Trapped between a friend who progressively sees him less and less as a friend and a group that sees him less and less as a guide, Iasonas will have to give an answer to all his personal questions regarding his sexuality and his career.', 2011, 10.0, '2025-12-12 16:16:45.545488', 'https://image.tmdb.org/t/p/w500/duQnk1HgS5ynbYhReKnvAH0vj3A.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (22148, 'Meat the Truth', 'Film', 'Documentary', 'Meat the Truth is a high-profile documentary which forms an addendum to earlier films on climate change. Although such films have succeeded in drawing public attention to the issue of global warming, they have repeatedly ignored one of the most important causes of climate change: the intensive livestock production. Meat the Truth draws attention to this by demonstrating that livestock farming generates more greenhouse gas emissions worldwide than all cars, lorries, trains, boats and planes added together.', 2008, 10.0, '2025-12-12 16:16:45.692343', 'https://image.tmdb.org/t/p/w500/ANTsGDien6MwXKndxObZQIoz3c.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (22313, 'Eggshells', 'Film', 'Fantasy, Drama', 'Experimental allegorical story about a group of hippie students in Austin, Texas, who move into an old big house in the woods. However, something else is there and it''s influencing them.', 1969, 10.0, '2025-12-12 16:16:47.019100', 'https://image.tmdb.org/t/p/w500/qlaGO8llKWfnmQhwDmNg6kczJ6J.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (23344, 'Bloodline', 'Film', 'Horror', 'Sandra''s twin sister was brutally murdered by a serial killer when they were children. Fifteen years later Sandra is now a professional journalist whose career is on the fritz. Sandra is given one last shot - an assignment which will prove the toughest of her life. She is sent back to the location of her sister''s murder to shoot a behind-the-scenes expose for a hardcore porn flick. There she will be forced to confront the ghosts of her past as a new copycat killer has his sights set on Sandra.', 2011, 10.0, '2025-12-12 16:16:55.670543', 'https://image.tmdb.org/t/p/w500/AnA1Jiuxjkm5GtqsanReFKhZX3T.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (23452, 'Slaying the Badger', 'Film', 'Documentary', 'Before Lance Armstrong, there was Greg LeMond, who is now the first and only American to win the Tour de France. In this engrossing documentary, LeMond looks back at the pivotal 1986 Tour, and his increasingly vicious rivalry with friend, teammate, and mentor Bernard Hinault. The reigning Tour champion and brutal competitor known as “The Badger,” Hinault ‘promised’ to help LeMond to his first victory, in return for LeMond supporting him in the previous year. But in a sport that purports to reward teamwork, it’s really every man for himself.', 2014, 10.0, '2025-12-12 16:16:56.596123', 'https://image.tmdb.org/t/p/w500/qkQ1h7W1h0V9ydcXXQ5ob1kGiR2.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (23895, 'The Bride from Hades', 'Film', 'Horror', 'On the night of the summer Obon festival, Hagiwara Shinzaburo meets a beautiful courtesan named Otsuyu. Not knowing she''s a ghost, he becomes infatuated by her.', 1968, 10.0, '2025-12-12 16:17:00.364073', 'https://image.tmdb.org/t/p/w500/xrejo0tLkgfNrpkHmBW2Tkm9IMR.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (24466, 'Double Tide', 'Film', '', 'Artist and filmmaker Sharon Lockhart is known for creating beautiful, meditative films that incorporate subtle movement and a static, photographic gaze to examine her subjects. Her new film, Double Tide, documents the work of a female clam digger in the mudflats of coastal Maine and is filmed on the rare occasion in which low tide occurs twice within daylight hours—once at dawn and once at dusk.', 2009, 10.0, '2025-12-12 16:17:05.417304', 'https://image.tmdb.org/t/p/w500/3WYMMQCv2Z2T3FjaZAcETplEzZ8.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (24814, 'The Great Kidnapping', 'Film', 'Crime', 'In early seventies Italy, plagued by criminality and political terrorism, a fearless police commissioner is sent to restore law and order in a northern industrial town devastated by a recent wave of violence and kidnappings..', 1973, 10.0, '2025-12-12 16:17:08.420709', 'https://image.tmdb.org/t/p/w500/mpJM5IjG47QCv3kGuQ8Mqfk0Jmb.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (25182, 'Symphony of the Soil', 'Film', 'Documentary, Adventure', 'Drawing from ancient knowledge and cutting edge science, Symphony of the Soil is an artistic exploration of the miraculous substance soil. By understanding the elaborate relationships and mutuality between soil, water, the atmosphere, plants and animals, we come to appreciate the complex and dynamic nature of this precious resource. The film also examines our human relationship with soil, the use and misuse of soil in agriculture, deforestation and development, and the latest scientific research on soil’s key role in ameliorating the most challenging environmental issues of our time. Filmed on four continents, featuring esteemed scientists and working farmers and ranchers, Symphony of the Soil is an intriguing presentation that highlights possibilities of healthy soil creating healthy plants creating healthy humans living on a healthy planet.', 2013, 10.0, '2025-12-12 16:17:11.586749', 'https://image.tmdb.org/t/p/w500/2ECOJwW7BvlH5w4sQf3nni4MqGv.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (26419, 'Willow and Wind', 'Film', 'Drama', 'A boy breaks a window at his school and sets out to fix it on his own during a storm.', 2000, 10.0, '2025-12-12 16:17:23.211041', 'https://image.tmdb.org/t/p/w500/mpO6dIP6hAGkniOMyH9NZ3Dz33O.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (26825, 'Vessel of Wrath', 'Film', 'Comedy, Drama, Romance', 'Ginger Ted, AKA Edward Claude Wilson (Charles Laughton) a drunkard and womanizer, and Miss Jones,(Elsa Lanchester) a missionary, live in the Alas Islands. During a cholera epidemic, Ginger Ted and Miss Jones are sent to an outlying part of the islands to run a hospital; on their return, their motorboat breaks down, and they are marooned overnight on a small island.', 1938, 10.0, '2025-12-12 16:17:27.506605', 'https://image.tmdb.org/t/p/w500/eEL8WAXMTkSr9p8TKeyTLtIb7ob.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (27781, 'The incredible Paris Incident', 'Film', 'Action, Adventure, Comedy, Science Fiction', 'Argoman has a silly costume and is a sexist pig. He uses his special telekinetic to get the ladies to sleep with him. The catch is, after a night with a gal he loses his special powers for 6 hours!  In this comedic super/spy thriller, Argoman goes head to head against the evil Jenabelle: Queen of the World.', 1967, 10.0, '2025-12-12 16:17:37.222603', 'https://image.tmdb.org/t/p/w500/rSEO8lJQytxur3FOId4XMfiVhE3.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (27870, 'Absolute Aggression', 'Film', 'Action, Science Fiction, Thriller', 'In the year 2011, the prison system is run by the private sector. Business tycoon R.D. Crowley (Robert Davi) has created a Virtual Reality prison. The prisoner''s bodies are locked in suspended animation while their mind traverses the lethal labyrinth of games Crowley has designed for them. Crowley allows wealthy sportsmen to participate, for a price, in deadly VR combat with the prisoners.', 2004, 10.0, '2025-12-12 16:17:38.188343', 'https://image.tmdb.org/t/p/w500/uFoDacIvDooPzoO8uKeMir9JOrk.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (28369, 'One Night Only', 'Film', 'Comedy', 'A group of female friends get together with some hired "ladies of the evening", and make some quick cash for throwing a raunchy party for the local hockey team.', 1986, 10.0, '2025-12-12 16:17:43.287545', 'https://image.tmdb.org/t/p/w500/oYAduyoeg3UWSzAvnGqagelLHTP.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (28385, 'Crooks and Coronets', 'Film', 'Comedy', 'Two crooks are hired to rob an eccentric old lady''s estate, but once they get to know her, they can''t bring themselves to do it.', 1969, 10.0, '2025-12-12 16:17:43.439336', 'https://image.tmdb.org/t/p/w500/wrLYTSVCwi2dYzyY95aFK8ZZnKV.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (28687, 'Garrison Keillor: The Man on the Radio in the Red Shoes', 'Film', '', 'Americas foremost humorist and commentator, Garrison Keillor, takes his skits and jokes, music and monologues across the country in his traveling radio show, spinning his stories into American gold. This free form, intimate look at the private man in the public spotlight goes behind the scenes of Americas most popular radio show, A Prairie Home Companion, and inside the imagination of the man who created it.', 2009, 10.0, '2025-12-12 16:17:46.618073', 'https://image.tmdb.org/t/p/w500/y65AKAO3vBlvKMZOm7aQ8XB4EiM.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (29154, 'At Ellen’s Age', 'Film', 'Drama', 'A German flight attendant''s life spirals downward after she leaves her husband, quits her job, and joins a radical group of animal rights activists.', 2010, 10.0, '2025-12-12 16:17:51.630881', 'https://image.tmdb.org/t/p/w500/oGF9hN2xYA4hHv6IxbXp03aYNW5.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (29194, 'Zodiac: The Race Begins...', 'Film', 'Animation, Adventure', 'Ringo the Rat (voice of Tom Arnold) and his pal Oriole the Ox compete in a big race, and discover that persistence and teamwork are just as important as speed when it comes to crossing the finish line first. Determined to thwart the plans of her long time enemy, the Jade Emperor, she sets forth to prevent the success of the Race be impeding the 12 chosen ones.', 2006, 10.0, '2025-12-12 16:17:52.010171', 'https://image.tmdb.org/t/p/w500/jAxhFxtz5Yf9PJfrPHzpVcDxcav.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (29288, 'Backyard Dogs', 'Film', 'Action, Comedy', 'Two teenage boys aspire to win a backyard wrestling championship and a chance to appear on a national TV show.', 2001, 10.0, '2025-12-12 16:17:53.099406', 'https://image.tmdb.org/t/p/w500/ayrCNUHTsk817uAvaK0bnqCyNO.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (29308, 'The Prospects', 'Film', '', 'In Brooklyn live two young street musicians who since childhood dream of building a recording studio together. Charlie, who plays the banjo, just inherited a house with a large basement. His best friend and manager Ted thinks it might be the perfect place for the studio but they need $ 25,000 to fulfill their dream. One day a Jamaican nurse approaches them on the street asking for help to lift a patient who has fallen down. Ted finds a collection of rare baseball cards in the house of the patient, and soon will plot a plan to steal the valuable collection to finance their studio. But when Charlie gets involved in a relationship with the nurse, Ted plans will be disrupted and his friendship with Charlie threatened.', 2011, 10.0, '2025-12-12 16:17:53.312950', 'https://image.tmdb.org/t/p/w500/jeEMgPjbZenscGSMLrdxrcGaQdu.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (29480, 'Intangible Asset Number 82', 'Film', 'Documentary', 'The search for an enigmatic South Korean shaman, and the inspiration found on the journey, renews a jazz musician''s faith in the power of music.', 2008, 10.0, '2025-12-12 16:17:55.089581', 'https://image.tmdb.org/t/p/w500/hYLHG5dBR3jr15wH9mDtj1xeYAs.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (30190, 'The Mother Of Invention', 'Film', 'Comedy', 'A mockumentary about an aspiring inventor who dreams of winning an annual young inventor award. The only problem is... he''s never made an invention that works.', 2010, 10.0, '2025-12-12 16:18:02.634519', 'https://image.tmdb.org/t/p/w500/rLBA5XEI7qlJey5ClAVOs9qKDk6.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (31672, 'Andrew Jenks, Room 335', 'Film', '', 'To get to know the world he lives in, college kid Andrew Jenks doesn''t take off to remote, exotic places with a backpack, but instead decides to go and stay in a retirement home in Florida for a few weeks. There, he gets acquainted with Tammy, Libby, Dotty and Bill, all of whom are past their prime. These few weeks turn into a valuable experience for Jenks, who approaches the elderly people with an open mind and takes a close look at the less cheerful sides of old age, including decay and dependence.', 2008, 10.0, '2025-12-12 16:18:16.763161', 'https://image.tmdb.org/t/p/w500/itlsSDdnkAHa2ZIY8SQIWLve6IK.jpg');
