INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (42543, 'Dream Deceivers: The Story Behind James Vance vs. Judas Priest', 'Film', '', 'A chilling post mortem on the tragic case of two teenagers who decided to shoot themselves in the head with a shotgun, and the ensuing court case staged to place the blame on the heavy metal band Judas Priest.', 1992, 10.0, '2025-12-12 16:18:26.606712', 'https://image.tmdb.org/t/p/w500/lssGutsue6PaWY1mHRVjq8e3B81.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46026, 'Great Transport', 'Film', 'War', 'This WW2 epic was one of the last movies of that kind made in former Yugoslavia. It tells the true story of great transport of Partizans from Vojvodina to Bosnia in 1943.', 1983, 10.0, '2025-12-12 16:18:36.855412', 'https://image.tmdb.org/t/p/w500/3en60tqKsRxhudOsuRAMZDnJrit.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46139, 'Poor, Poor Pavel', 'Film', 'Drama, Foreign', 'Lenfilm''s most recent major production spins a kind of historical fantasy based on real incidents that''s full of ominous implications for today. One night, a patrol rushes into the chambers of the Russian prince Pavel, son of the Empress Catherine; the Empress has died, and Pavel is to be anointed the new Tsar. Thought to be feeble-minded at best and crazy at worst, Pavel soon lives up to his enemies'' fears: he dismisses long-serving courtiers, demands that peasants only work three days a week, and declares that state officials should start their days at 5 am. Soon, it seems that everyone who can is trying to hatch some kind of plot against him - including his own sons. Sumptuously designed, POOR POOR PAVEL constrasts the imperial splendor of the court with the sordid atmosphere of conspiracies and backstabbing that comes to define these characters'' lives.', 2003, 10.0, '2025-12-12 16:18:38.149186', 'https://image.tmdb.org/t/p/w500/1GyidIR1zmmWLn0ASUsOgZmfM06.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46145, 'Sentimentalnyy roman', 'Film', '', 'Near the close of the Russian Civil War, in 1923, a young man begins studying journalism at a worker newspaper and has a series of romantic adventures which cause him to mature swiftly. He rescues a beautiful girl from an abusive family situation, only to lose her to a smooth-talking sharpster the first time he has to leave town on assignment. Another much nicer and more principled girl is really in love with him, but he doesn''t know it. This bittersweet coming-of-age story was based on a novel by Vera Panova.', NULL, 10.0, '2025-12-12 16:18:38.214357', 'https://placehold.co/300x450/9b59b6/ffffff/png?text=Sentimentalnyy%20roman');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46238, 'Brave Revolutionary', 'Film', '', 'Lack-lustred and alcoholic Pratap Narayan Tilak is given a rude awakening when he meets with journalist Megha Dixit, and decides to instill some sense of justice and fair play within his community, and get them to assertively defend their rights and freedom. He is met with strong resistance, both from within his very own community, the police, and some very powerful and influential politicians. Unable to bear the injustice, and frustrated at his community to act proactively, Pratap decides to take the law into his own hands, resulting in chaos, violence, and uncertainty for everyone, and a path to his own grave.', 1994, 10.0, '2025-12-12 16:18:39.312295', 'https://image.tmdb.org/t/p/w500/zAb2YxgYSJTcloGTHAA9ogOVq7M.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46556, 'The Secret of Queen Anna or Musketeers 30 Years Later', 'Film', 'Adventure', 'The 3rd part of the famous trilogy by Alexandre Dumas about d''Artagnan and his 3 friends Athos, Porthos and Aramis.', 1993, 10.0, '2025-12-12 16:18:43.096502', 'https://image.tmdb.org/t/p/w500/l7tgXN4iRWFNYAhgFXhBG8ERawr.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46564, '713-й просит посадку', 'Film', 'Action, Drama', '', 1961, 10.0, '2025-12-12 16:18:43.178436', 'https://image.tmdb.org/t/p/w500/6vkoPXy5d36GQhJ8CJ8LYbxy3og.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46803, 'The House Across the Street', 'Film', 'Horror, Thriller', 'Amy has moved east from Kansas, determined to start a new life. She thinks she has found the perfect small quiet town, a great neighborhood on a quiet street. As she moves into her brand new apartment, eager to start a dream job, happy to befriend her neighbors, she finds out that not everything is as it seems, especially at the house across the street.', 2015, 10.0, '2025-12-12 16:18:45.904210', 'https://image.tmdb.org/t/p/w500/pzTtfN1srzSqWZFvPneV68la5lO.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (46813, 'Souls of Zen: Ancestors and Agency in Contemporary Japanese Temple Buddhism', 'Film', 'Documentary', 'The Japanese population’s reaction to the catastrophe of March 2011 has been described as “stoic” by the Western media. The Japanese code of conduct is indeed deeply rooted in their Buddhist traditions, and young filmmakers Tim Graf and Jakob Montrasio observe in detail what this means for the people and their religion. At graveyards, in temples, at monasteries and with families, they question the impact this triple affliction has had on the lives and beliefs of the inhabitants. How deeply do their beliefs affect their grieving? What role do the monks play in assisting people with their grief? And, what effects has this enormous catastrophe had on their religious rituals? SOULS OF ZEN inserts the events of March 2011 into the context of traditional Zen Buddhism, examining Japan’s religiousness and the beliefs of those practising it at a crucial turning point.', 2012, 10.0, '2025-12-12 16:18:46.012723', 'https://image.tmdb.org/t/p/w500/rS8N0od43nCXmXJfUEV8MuFs3NL.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (47363, 'Cheer Cheer Cheer!', 'Film', 'Comedy', 'Momoko (Yui Aragaki) is a quiet and lonely high school girl who''s only passion is to cheer traditional cheer squad, but all she could gather were good for nothing guys, who could not find places in school. They start the cheer squad with a disaster, but when they finally find the true meaning of "cheering" someone, their passion becomes power and gives strength to those that are cheered.', 2008, 10.0, '2025-12-12 16:18:52.388086', 'https://image.tmdb.org/t/p/w500/uORlSC0O38d8hUc8pMdt0v9vQrk.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (47814, 'Looking for Grace', 'Film', 'Drama', 'When rebellious 16-year-old Grace takes off, her exasperated mum and dad enlist the help of a close-to-retirement detective, and begin the long drive from Perth out to the West Australian wheatbelt to try to find her. On the journey, the two must confront the realities of their changing relationship to one another, and to their daughter…', 2016, 10.0, '2025-12-12 16:18:57.782264', 'https://image.tmdb.org/t/p/w500/dDTE3PgHmWu6XPsTTlnDLsYOVKs.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (48331, 'Acéphale', 'Film', '', 'In common with other Zanzibar films, Patrick Deval’s Acéphale (1968) eschews conventional narrative in favour of an experimental arrangement of austerely executed but intensely hallucinatory episodes that build into a nightmarish fever of isolation and hopelessness.', 1969, 10.0, '2025-12-12 16:19:04.284490', 'https://image.tmdb.org/t/p/w500/gaU8bANlV3JgWIlpqRQmc0HxY2s.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (48784, 'Shuttlecock Boys', 'Film', 'Drama', 'Shuttlecock Boys revolves around the lives, successes and failures of four friends who hail from lower-middle-class backgrounds in Delhi. Should we accept what life offers to us on a platter or should we try to chase our dreams, taking the path less taken? That’s the question our protagonists Gaurav, Manav, Pankaj and Loveleen seek answer to, as they decide to embark upon an eventful journey that will change the course of their lives and careers forever. The one thing that unites these four friends is their common love for badminton. Every evening they meet for a couple of games in their neighborhood joking about their lives and pulling each other’s legs. This part of the day is the most pleasant part of their otherwise dreary lives. While playing badminton one such night, they decide to do something on their own. This very attempt becomes their lifeline putting them on a litmus test of determination, courage, luck and spirit of friendship.', 2012, 10.0, '2025-12-12 16:19:09.937595', 'https://image.tmdb.org/t/p/w500/dMHdKTqlhesbooLvjZqhEW8Igt0.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (48980, 'Images of a Relief', 'Film', 'War, Drama', 'Set in Copenhagen during World War II, the film follows a German officer who visits his Danish mistress in the days after the occupation of Denmark has ended.', 1982, 10.0, '2025-12-12 16:19:12.458737', 'https://image.tmdb.org/t/p/w500/goBlGXlywd7h45QHlqMJnoJ9x5I.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (49032, 'A Story of the Forest: Mavka', 'Film', 'Drama, Fantasy, Romance', 'Mavka, a water nymph, loves Lukash, a country youth. Their brief happiness ends when Lukash is forced to marry the shrewish Kilina. The Spirit of the Forest turns Lukash into a wolf as punishment for his infidelity. The strength of Mavka''s love breaks the spell, but Kilina curses the nymph, transforming her into a weeping willow. This beautiful and tragic story is based on a play written in 1912 by Lesya Ukrainka, a Ukrainian poet, writer and political, civil and female activist, and includes mythological characters taken from Ukrainian folklore.', 1980, 10.0, '2025-12-12 16:19:13.118428', 'https://image.tmdb.org/t/p/w500/yXV8SXQXC657jsaWB7DZKwO1u5F.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (49087, 'Godheten', 'Film', 'Documentary', '', 2013, 10.0, '2025-12-12 16:19:13.827147', 'https://image.tmdb.org/t/p/w500/pQ8w65ee1Bc6lJDHvlIqYaAvKrq.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (49203, 'God is on Air', 'Film', 'Comedy, Drama', 'Two Spanish pan-handlers soon find themselves in over their heads when they stumble upon an opportunity to redeem themselves and perhaps the entire planet. The world appears to suffer from rampant poverty, violence and spiritual desperation and the relentless news media force-feeds these images to the Spanish people. A popular reality television show lets the audience decide between life or death for suspected felons, and one of the opportunistic pan-handlers attempts to escape poverty through this raucous and sensational TV program.', 2002, 10.0, '2025-12-12 16:19:15.294946', 'https://image.tmdb.org/t/p/w500/fbT2FJE8hNuz6rc2c3fQwGIw15W.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (49223, 'Kenny Chesney: Summer In 3D', 'Film', '', 'Kenny Chesney summer tour concert', 2010, 10.0, '2025-12-12 16:19:15.532854', 'https://image.tmdb.org/t/p/w500/7GCsndH3whUeHTTi0pMaCxkqWFS.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (49288, 'Love at 16', 'Film', 'Drama, Comedy', '', 2004, 10.0, '2025-12-12 16:19:16.356461', 'https://image.tmdb.org/t/p/w500/7mC74RTIDunweK56dVqD6ZqMEoe.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (50507, 'Ladies'' Doctor', 'Film', 'Comedy', 'Dr. Lo Bianco, debt load, flees abroad and the headquarters avviatissimo study gynecological colleague Giovannaldi. These are adept at gaining the trust of high society and, thanks to the relationship established with the wife of a wealthy manufacturer (enough to get her pregnant), she becomes finance, own the cuckolded husband, a luxury clinic. And there will be a prize for Lobianco.', 1977, 10.0, '2025-12-12 16:19:31.973349', 'https://image.tmdb.org/t/p/w500/oECIfdYgw6fEa02xrp3zRYh4xOG.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (50622, 'Dead Run', 'Film', '', 'The story concerns a boy called Shuji, growing up in a rural area of Japan where the community is divided into "Shore" and "Offshore" - the latter so-named because it is built on reclaimed land. He meets a few main characters, besides his family, that shape his development - gangster Oni-ken (Susumu Terajima) and his hostess girlfriend, an ominous-looking Catholic priest and his congregation-of-one, the troubled and rebellious teenage girl Eri - who also becomes Shuji''s classmate and the object of his adolescent affections. Life in the Shore/Offshore community is not a bundle of joy - the impression is of a community and lifestyle in decay, with the only hope of rejuvenation being a gangster-funded hotel development project that doesn''t exactly inspire the locals either. It''s an environment that does not fill its young inhabitants with much hope or inspiration.', 2005, 10.0, '2025-12-12 16:19:33.524657', 'https://image.tmdb.org/t/p/w500/kn6V4bXBfmz1EDi6dvtTG9jDBLg.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51121, 'The Dragon Lives Again', 'Film', 'Fantasy, Action', 'Everyone''s favorite martial artist ""Bruce"" winds up fighting for his life and soul in hell against an evil Warlord intent on making him mincemeat - and he has recruited some of the 1970s most iconic B-movie characters to help dispatch the great one. But when that won''t do the trick, he uses monsters, mummies and beautiful women to get the little dragon at any cost.', 1977, 10.0, '2025-12-12 16:19:40.222577', 'https://image.tmdb.org/t/p/w500/lPurIwsLJxYxSxlqGpECeA6FtAB.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51142, 'American Hostage', 'Film', 'Thriller, Crime, Drama', 'American Hostage pulls back the curtains on a terrorist plot centered on a group of terrorists holding two American soldiers hostage on U.S. soil. They demand the release of all prisoners of Guantanamo Bay or they will kill the soldiers.', 2016, 10.0, '2025-12-12 16:19:40.517819', 'https://image.tmdb.org/t/p/w500/r5wkDzVPqoho8Iy4XOvYeFGI31P.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51187, 'Sunnyside Up', 'Film', 'Comedy, Music', 'Molly and Bee, sweet young ''working girls,'' live in a cheap room over a New York grocery store. Molly''s idol, wealthy Jack Cromwell, lives in a Long Island mansion but is markedly less happy, since his fiancée Jane won''t discourage her other admirers. Fleeing in his car, Jack ends up in an urban block party where he meets you-know-who.', 1929, 10.0, '2025-12-12 16:19:41.198605', 'https://image.tmdb.org/t/p/w500/ypfjEPNjxJhhgRbCA1STQCCPcR6.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51266, 'Bazodee', 'Film', 'Romance, Drama, Music', 'Set in beautiful Trinidad and Tobago, BAZODEE is a Bollywood style Caribbean musical about being true to yourself and honest in love at all costs.', 2016, 10.0, '2025-12-12 16:19:42.291562', 'https://image.tmdb.org/t/p/w500/e4BsUZ7gPbDIDybmXUr5HvI9LFr.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51276, 'King: A Filmed Record... Montgomery to Memphis', 'Film', 'Documentary', 'A 1970 American documentary film biography of Dr. Martin Luther King, Jr., presented in the form of newsreel footage and segments of recordings by Dr. King, framed by celebrity narrators, including Marlon Brando, Paul Newman, Joanne Woodward, Ruby Dee, James Earl Jones, Clarence Williams III, Burt Lancaster, Ben Gazzara, Charlton Heston, Harry Belafonte, The movie was produced by Richard Kaplan and Ely Landau.', 1970, 10.0, '2025-12-12 16:19:42.442134', 'https://image.tmdb.org/t/p/w500/jeld2y4CsLIvFhiRVom7Thuw7eo.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51763, 'Mamaboy', 'Film', 'Comedy, Drama, Family, Fantasy, Romance, Science Fiction', 'A high school student must hide the fact that he has become pregnant from his family, friends and the school faculty!', 2017, 10.0, '2025-12-12 16:19:49.160157', 'https://image.tmdb.org/t/p/w500/ocsSTZEAbNuz68yqsfbOFlas9N4.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51802, 'People of a Feather', 'Film', 'Documentary', 'The Inuit of Belcher Islands struggle to adapt as their environment changes.', 2012, 10.0, '2025-12-12 16:19:49.698132', 'https://image.tmdb.org/t/p/w500/pn9OfsADQ7xEgalyjeGQPD9Knvo.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (51813, 'Siccin 3: Cürmü Ask', 'Film', 'Horror', 'After a terrible car accident, Sedat will do anything to save a childhood friend – even if it means dealing with demons and ghosts.', 2016, 10.0, '2025-12-12 16:19:49.843963', 'https://image.tmdb.org/t/p/w500/du3PLNB2L8BNshxCOrgfDVyDfV2.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (52101, 'Farewell Baghdad', 'Film', 'Drama', 'Between the years 1950-51 close to 130 thousand Jews left Iraq. The most ancient community in the world ceased to exist.', 2014, 10.0, '2025-12-12 16:19:53.941016', 'https://image.tmdb.org/t/p/w500/lwNLiewOdoGUedZYNc8Ac9mQo7o.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (52112, 'My Night, Your Day', 'Film', 'Crime, Comedy', 'Novák cannot sleep. Not to disturb his girlfriend, he spends his nights in the streets of Budapest and gets into weirder and weirder, more and more impossible and dangerous situations and liaisons. Unless he dies, he may regain his dreams by them.', 2015, 10.0, '2025-12-12 16:19:54.110727', 'https://image.tmdb.org/t/p/w500/jRf2hdMBZyeN703mLaXGOvc1Yla.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (52799, 'The Wild East', 'Film', '', 'The Solar Children, a group of dwarves who left the circus, are trying to start a settlement in the Kyrgyzstan wilderness just after the breakup of the Soviet Union, but are harassed by a gang of bikers. With their meager savings, they hire a ragtag group of heroes to drive off the bikers.', 1993, 10.0, '2025-12-12 16:20:03.824859', 'https://image.tmdb.org/t/p/w500/uUeRz39WxUyhgxFEXEY9PlW8rto.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (52860, 'My Future Love', 'Film', 'Comedy, Drama', 'In 1973, the 20-year-old Svante has a heart condition that the doctors cannot fix. When he has a breakdown on a subway platform, a strange train suddenly appears. He steps into the subway car filled with wonder, without knowing that the destination is the future. In the future he meets Elsa and together they must solve Svante''s problems and figure out how to live together when they are from two different eras.', 2016, 10.0, '2025-12-12 16:20:04.662976', 'https://image.tmdb.org/t/p/w500/chcWPwYgWDnUcoNWXmnlxr5vWzD.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (52953, 'Крепость: щитом и мечом', 'Film', 'War, Animation, Adventure', '', 2015, 10.0, '2025-12-12 16:20:05.901278', 'https://image.tmdb.org/t/p/w500/nwZW2x0uTEwJbOEAy7Gq34QV14q.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53055, 'Bella Vita', 'Film', 'Documentary', 'Bella Vita is an intimate and powerful journey of self-discovery, seeped in culture, tradition, and passion- where family comes first.', 2014, 10.0, '2025-12-12 16:20:07.382638', 'https://image.tmdb.org/t/p/w500/vP44XvOr4If17tme8mRInysCxY2.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53127, 'Panorama of Esplanade by Night', 'Film', '', 'A most perfect picture of the Pan-American Exposition buildings, including the Electric Tower and Temple of Music, as they appear at night.', 1901, 10.0, '2025-12-12 16:20:08.422108', 'https://placehold.co/300x450/f1c40f/ffffff/png?text=Panorama%20of%20Esplanade%20by%20Night');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53363, 'The Black Sheep of Whitehall', 'Film', 'Comedy', 'A professor teaching at a correspondence school  discovers that a Nazi agent is trying to prevent a trade treaty being signed between England and South America.', 1942, 10.0, '2025-12-12 16:20:11.789036', 'https://image.tmdb.org/t/p/w500/dqASaLG6ACSHTFOiHod2LrI6Zzi.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53638, 'Has the Film Already Started?', 'Film', '', '“A pink moving screen will stand at the entrance to the theatre, in the night. One hour before the screening a projectionist will show Griffith’s Intolerance on this screen. The start of the film will be announced at 8.30 but no one will enter before 9.30. During these 60 minutes of waiting, people on the first floor of the building will shake out very dusty carpets, and someone else will throw ice water on the heads of those spectators waiting for the screening. Some actors who have infiltrated the crowd will insult other actors on the first floor. At this moment only, and to stop the beginning of a scandal, the doors of the theatre will open…”', 1951, 10.0, '2025-12-12 16:20:16.179578', 'https://image.tmdb.org/t/p/w500/vzg8m4H2JHiQsCP82vBEjrWnw0r.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53676, 'American Sharia', 'Film', 'Drama, Comedy', 'Fast paced, action packed comedy. Tension flares in The Motor City as Officer Richardson profiles every Muslim he sees as a terrorist. He goes on an arrest frenzy, which makes the community activists, Jihad and Osama take to the streets and rally the people to stand up for their rights. The Chief of Police wants to gain the trust of the Muslim community in order to get re-elected, but Attorney Leila Rodriguez is standing in the way with a discrimination law suit against Officer Richardson and the Motor City Police Department. The Chief calls on his most unreliable detective, Mohammed and partners him with a Middle Eastern, Sharia Law fanatic, Detective Abdul. The Chief wants them to "Speak Muslim To The Muslims" which he thinks will guarantee his re-election.  - Written by Omar Regan', 2015, 10.0, '2025-12-12 16:20:16.742541', 'https://image.tmdb.org/t/p/w500/ad7FHjEN89k9ivwNPSUZebswuZd.jpg');
INSERT INTO icerikler (id, baslik, tur, kategoriler, ozet, yil, imdb_puani, olusturma_tarihi, poster_url) VALUES (53911, 'Christopher Titus: Angry Pursuit of Happiness', 'Film', 'Comedy', 'Known as one of the best and most prolific comedians working today, Christopher Titus releases his sixth 90-minute comedy special, The Angry Pursuit of Happiness, his best performance to date. The show takes the audience on a wild ride from Titus’ solution to the world’s problems,he fixes everything in a way you wont believe, to his insight on “Here’s how life goes” to his ‘me-logy,’ where Titus gives his own eulogy. Titus takes this special to new comedic places he hasn’t gone yet. At an hour and 45 minutes it’s double what a normal special brings, as Titus says “We need comedy to get rid of our desire to kill”', 2014, 10.0, '2025-12-12 16:20:20.455564', 'https://image.tmdb.org/t/p/w500/qqnBOOoVweSp8kedelpWIJKRl5n.jpg');
