PRAGMA foreign_keys = OFF;
BEGIN TRANSACTION;
DROP TABLE IF EXISTS icerikler;
CREATE TABLE icerikler (
	id INTEGER NOT NULL, 
	baslik VARCHAR NOT NULL, 
	tur VARCHAR NOT NULL, 
	kategoriler VARCHAR, 
	ozet TEXT, 
	yil INTEGER, 
	imdb_puani FLOAT, 
	olusturma_tarihi DATETIME, poster_url TEXT, 
	PRIMARY KEY (id)
);
DROP TABLE IF EXISTS puanlar;
CREATE TABLE puanlar (
	id INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT, 
	kullanici_id INTEGER NOT NULL, 
	icerik_id INTEGER NOT NULL, 
	puan INTEGER NOT NULL, 
	puanlama_tarihi DATETIME, 
	FOREIGN KEY(kullanici_id) REFERENCES kullanicilar (id), 
	FOREIGN KEY(icerik_id) REFERENCES icerikler (id)
);
DROP TABLE IF EXISTS movies;
CREATE TABLE "movies" (
"adult" TEXT,
  "belongs_to_collection" TEXT,
  "budget" TEXT,
  "genres" TEXT,
  "homepage" TEXT,
  "id" TEXT,
  "imdb_id" TEXT,
  "original_language" TEXT,
  "original_title" TEXT,
  "overview" TEXT,
  "popularity" TEXT,
  "poster_path" TEXT,
  "production_companies" TEXT,
  "production_countries" TEXT,
  "release_date" TEXT,
  "revenue" REAL,
  "runtime" REAL,
  "spoken_languages" TEXT,
  "status" TEXT,
  "tagline" TEXT,
  "title" TEXT,
  "video" INTEGER,
  "vote_average" REAL,
  "vote_count" REAL
);
DROP TABLE IF EXISTS shows;
CREATE TABLE "shows" (
"show_id" TEXT,
  "type" TEXT,
  "title" TEXT,
  "director" TEXT,
  "cast" TEXT,
  "country" TEXT,
  "date_added" TEXT,
  "release_year" INTEGER,
  "rating" TEXT,
  "duration" TEXT,
  "listed_in" TEXT,
  "description" TEXT
);
DROP TABLE IF EXISTS books;
CREATE TABLE "books" (
"bookID" INTEGER,
  "title" TEXT,
  "authors" TEXT,
  "average_rating" REAL,
  "isbn" TEXT,
  "isbn13" INTEGER,
  "language_code" TEXT,
  "  num_pages" INTEGER,
  "ratings_count" INTEGER,
  "text_reviews_count" INTEGER,
  "publication_date" TEXT,
  "publisher" TEXT
);
DROP TABLE IF EXISTS kullanicilar;
CREATE TABLE kullanicilar (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            kullanici_adi TEXT UNIQUE NOT NULL,
            email TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            olusturma_tarihi TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        , is_admin INTEGER DEFAULT 0);
DROP TABLE IF EXISTS yorumlar;
CREATE TABLE yorumlar (
	id INTEGER NOT NULL, 
	kullanici_id INTEGER NOT NULL, 
	icerik_id INTEGER NOT NULL, 
	yorum_metni TEXT NOT NULL, 
	olusturma_tarihi DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(kullanici_id) REFERENCES kullanicilar (id), 
	FOREIGN KEY(icerik_id) REFERENCES icerikler (id)
);
DROP TABLE IF EXISTS password_reset_tokens;
CREATE TABLE password_reset_tokens (
	id INTEGER NOT NULL, 
	kullanici_id INTEGER NOT NULL, 
	token VARCHAR NOT NULL, 
	expires_at DATETIME NOT NULL, 
	used INTEGER, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(kullanici_id) REFERENCES kullanicilar (id)
);
DROP TABLE IF EXISTS chat_history;
CREATE TABLE chat_history (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            kullanici_id INTEGER NOT NULL,
            message TEXT NOT NULL,
            is_user INTEGER DEFAULT 1,
            timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY(kullanici_id) REFERENCES kullanicilar(id)
        );
CREATE INDEX ix_icerikler_baslik ON icerikler (baslik);
CREATE INDEX ix_icerikler_tur ON icerikler (tur);
CREATE INDEX ix_icerikler_id ON icerikler (id);
CREATE INDEX ix_puanlar_id ON puanlar (id);
CREATE INDEX ix_yorumlar_id ON yorumlar (id);
CREATE UNIQUE INDEX ix_password_reset_tokens_token ON password_reset_tokens (token);
CREATE INDEX ix_password_reset_tokens_id ON password_reset_tokens (id);
CREATE INDEX idx_chat_history_kullanici_id ON chat_history (kullanici_id);
